+            &stages,
+            |b, &stages| {
+                let chain: Vec<(String, u32, u32)> = (0..stages)
+                    .map(|i| (format!("stage_{i}"), i as u32, (i + 1) as u32))
+                    .collect();
+                b.iter(|| {
